import nodemailer from 'nodemailer';
import dotenv from 'dotenv';
dotenv.config();
const transporter = nodemailer.createTransport({
    host: process.env.SMTP_HOST || 'smtp.gmail.com',
    port: parseInt(process.env.SMTP_PORT || '587'),
    secure: false,
    auth: {
        user: process.env.SMTP_USER,
        pass: process.env.SMTP_PASS,
    },
});
const formatCurrency = (amount) => new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR' }).format(amount);
export const sendInvoiceEmail = async (data) => {
    const subject = `Invoice Request – ${data.clientName} – ${data.invoiceDate} – ${data.assignmentRef}`;
    const html = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; background: #f4f4f4; margin: 0; padding: 20px; }
    .container { background: white; max-width: 700px; margin: 0 auto; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }
    .header { background: #1e3a5f; color: white; padding: 24px 32px; }
    .header h1 { margin: 0; font-size: 20px; }
    .header p { margin: 4px 0 0; opacity: 0.8; font-size: 14px; }
    .body { padding: 24px 32px; }
    table { width: 100%; border-collapse: collapse; margin-top: 16px; }
    th { background: #f0f4f8; text-align: left; padding: 10px 12px; font-size: 13px; color: #555; border: 1px solid #ddd; }
    td { padding: 10px 12px; border: 1px solid #ddd; font-size: 14px; }
    td:first-child { font-weight: 600; color: #333; width: 220px; }
    .total-row td { background: #e8f4e8; font-weight: bold; }
    .footer { background: #f7f9fc; padding: 16px 32px; font-size: 12px; color: #888; border-top: 1px solid #e0e0e0; }
    .badge { display: inline-block; padding: 3px 10px; border-radius: 12px; font-size: 12px; background: #e3e8ff; color: #3730a3; font-weight: 600; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>🧾 Invoice Request — Kirtane &amp; Pandit LLP</h1>
      <p>Generated by: ${data.managerName} &nbsp;|&nbsp; ${new Date().toLocaleString('en-IN')}</p>
    </div>
    <div class="body">
      <p>Dear Manisha,</p>
      <p>Please find below the invoice details for processing:</p>
      <table>
        <tr><th colspan="2">Invoice Details</th></tr>
        <tr><td>Client Name</td><td><strong>${data.clientName}</strong></td></tr>
        <tr><td>Invoice Date</td><td>${data.invoiceDate}</td></tr>
        <tr><td>UDIN (if applicable)</td><td>${data.udin || 'N/A'}</td></tr>
        <tr><td>Kind Attention</td><td>${data.kindAttention}</td></tr>
        <tr><td>Reference</td><td>${data.reference}</td></tr>
        <tr><td>Address</td><td>${data.address}</td></tr>
        <tr><td>GST No.</td><td>${data.gstNo}</td></tr>
        <tr><td>New Sales Ledger Heads</td><td>${data.newSalesLedger || 'N/A'}</td></tr>
        <tr><td>Narration</td><td>${data.narration}</td></tr>
        <tr><td>Amount of Professional Fees</td><td>${formatCurrency(data.professionalFees)}</td></tr>
        <tr><td>Out of Pocket Expenses</td><td>${formatCurrency(data.outOfPocket)}</td></tr>
        <tr class="total-row"><td>Net Amount (Rs.)</td><td>${formatCurrency(data.netAmount)}</td></tr>
      </table>
      <br/>
      <p><span class="badge">Assignment Category: ${data.category}</span> &nbsp; <span class="badge">Billing Cycle: ${data.billingCycle}</span>${data.batchId ? ` &nbsp; <span class="badge">Batch: ${data.batchId}</span>` : ''}</p>
    </div>
    <div class="footer">
      This is an automated email from the KP Audit Management System. Please do not reply to this email.
    </div>
  </div>
</body>
</html>`;
    const mailOptions = {
        from: `"KP AMS" <${process.env.SMTP_FROM}>`,
        to: process.env.ACCOUNTS_EMAIL,
        cc: data.managerEmail,
        subject,
        html,
    };
    if (!process.env.SMTP_USER || !process.env.SMTP_PASS) {
        console.log('[Email stub] Would send:', subject);
        return { success: true, stubbed: true };
    }
    await transporter.sendMail(mailOptions);
    return { success: true, stubbed: false };
};
